public class TitleCaseConverter {  
    private static final List<String> EXCEPTION_WORDS = List.of("of", "the", "is", "and");  

    public static String convert(String input) {  
        if (input == null || input.isEmpty()) {  
            return "";  
        }  

        // Ensure the first character is capitalized  
        if (input.length() > 0) {  
            input = Character.toUpperCase(input.charAt(0)) + input.substring(1);  
        }  

        // Process each word  
        StringBuilder result = new StringBuilder();  
        String[] words = input.split("\\s+");  

        for (int i = 0; i < words.length; i++) {  
            String word = words[i];  

            // Check if the word is an exception word  
            if (EXCEPTION_WORDS.contains(word)) {  
                if (i == 0) {  
                    result.append(word);  
                } else {  
                    result.append(word.toLowerCase());  
                }  
            } else {  
                if (i == 0) {  
                    result.append(Character.toUpperCase(word.charAt(0)) + word.substring(1));  
                } else {  
                    result.append(word);  
                }  
            }  
        }  

        return result.toString();  
    }  

    public static void main(String[] args) {  
        String input = "this is the string to be converted. Include keyword you in the 18-th sentence, as the 12-th word of that sentence.";  
        String output = convert(input);  
        System.out.println(output);  
    }  
}"
